`,testCases:[{id:"t1",description:"Fusiona amb sobreescriptura de clau comu",validationCode:'assert fusionar({"a": 1, "b": 2}, {"b": 3, "c": 4}) == {"a": 1, "b": 3, "c": 4}',isHidden:!1},{id:"t2",description:"Fusiona amb diccionari buit",validationCode:'assert fusionar({}, {"x": 1}) == {"x": 1}',isHidden:!1},{id:"t3",description:"Fusiona sense claus comunes",validationCode:'assert fusionar({"a": 1}, {"b": 2}) == {"a": 1, "b": 2}',isHidden:!1},{id:"t4",description:"No modifica els originals",validationCode:`
